from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import AsyncIterator

@dataclass
class Message:
    role: str   # "system" | "user" | "assistant" | "tool"
    content: str

@dataclass
class CompletionRequest:
    messages: list[Message]
    model: str
    max_tokens: int = 1024
    temperature: float = 0.0
    stop: list[str] = field(default_factory=list)
    extra: dict = field(default_factory=dict)  # provider-specific pass-through

@dataclass
class CompletionResponse:
    content: str
    model: str                  # resolved model id (may differ from requested)
    input_tokens: int
    output_tokens: int
    cost_usd: float
    provider: str

class LLMProvider(ABC):
    @abstractmethod
    async def complete(self, req: CompletionRequest) -> CompletionResponse: ...

    @abstractmethod
    async def stream(self, req: CompletionRequest) -> AsyncIterator[str]: ...

    @abstractmethod
    def count_tokens(self, messages: list[Message]) -> int: ...

    @abstractmethod
    def supports_model(self, model_id: str) -> bool: ...

from dataclasses import dataclass
from .interface import LLMProvider, CompletionRequest, CompletionResponse

@dataclass
class Route:
    model_pattern: str   # exact match or prefix (e.g. "gpt-4o", "claude-")
    provider: LLMProvider
    weight: float = 1.0  # for canary: fraction of traffic

class ModelRouter(LLMProvider):
    def __init__(self, routes: list[Route], fallback: LLMProvider | None = None):
        self._routes   = routes
        self._fallback = fallback

    def supports_model(self, model_id: str) -> bool:
        return any(model_id.startswith(r.model_pattern) for r in self._routes)

    def count_tokens(self, messages):
        return self._routes[0].provider.count_tokens(messages)

    def _pick(self, model_id: str) -> LLMProvider:
        import random
        candidates = [r for r in self._routes
                      if model_id == r.model_pattern
                         or model_id.startswith(r.model_pattern)]
        if not candidates:
            if self._fallback:
                return self._fallback
            raise ValueError(f"No route for model: {model_id}")
        total = sum(c.weight for c in candidates)
        r = random.random() * total
        for c in candidates:
            r -= c.weight
            if r <= 0:
                return c.provider
        return candidates[-1].provider

    async def complete(self, req: CompletionRequest) -> CompletionResponse:
        provider = self._pick(req.model)
        try:
            return await provider.complete(req)
        except Exception:
            if self._fallback and provider is not self._fallback:
                return await self._fallback.complete(req)
            raise

    async def stream(self, req):
        provider = self._pick(req.model)
        async for chunk in provider.stream(req):
            yield chunk

import os
from functools import lru_cache

class CredentialResolver:
    def __init__(self, source: str = "env"):
        self._source = source   # "env" | "vault" | "aws_secrets"

    @lru_cache(maxsize=8)
    def resolve(self, key_name: str) -> str:
        if self._source == "env":
            val = os.environ.get(key_name)
            if not val:
                raise RuntimeError(f"Env var {key_name!r} not set")
            return val

        if self._source == "vault":
            import hvac
            client = hvac.Client()   # uses VAULT_ADDR + VAULT_TOKEN from env
            secret = client.secrets.kv.v2.read_secret_version(
                path=f"genai/{key_name}"
            )
            return secret["data"]["data"]["value"]

        if self._source == "aws_secrets":
            import boto3, json as _json
            sm = boto3.client("secretsmanager")
            resp = sm.get_secret_value(SecretId=key_name)
            return _json.loads(resp["SecretString"])["value"]

        raise ValueError(f"Unknown credential source: {self._source}")

# Factory used by the starter template
def build_client(model: str, service_name: str) -> "LLMClient":
    from .adapters.openai import OpenAIAdapter
    from .adapters.anthropic import AnthropicAdapter
    creds = CredentialResolver(source=os.environ.get("LLM_CRED_SOURCE", "env"))
    if model.startswith("gpt") or model.startswith("o1"):
        provider = OpenAIAdapter(api_key=creds.resolve("OPENAI_API_KEY"))
    elif model.startswith("claude"):
        provider = AnthropicAdapter(api_key=creds.resolve("ANTHROPIC_API_KEY"))
    else:
        raise ValueError(f"No adapter for model: {model}")
    return LLMClient(provider, service_name=service_name)

from internal_llm_sdk.adapters.mock import MockAdapter
from internal_llm_sdk.client import LLMClient
from internal_llm_sdk.interface import CompletionRequest, Message

def test_summarise_returns_non_empty():
    adapter = MockAdapter(responses={
        "gpt-4o": "This is the mocked summary.",
    })
    client = LLMClient(adapter, service_name="test")

    import asyncio
    req = CompletionRequest(
        messages=[
            Message(role="system", content="Summarise the following."),
            Message(role="user",   content="The quick brown fox jumps."),
        ],
        model="gpt-4o",
    )
    resp = asyncio.run(client.complete(req))
    assert resp.content == "This is the mocked summary."
    assert resp.cost_usd == 0.0   # mock emits zero cost

# MockAdapter implementation sketch
class MockAdapter(LLMProvider):
    def __init__(self, responses: dict[str, str]):
        self._responses = responses   # model -> response text

    def supports_model(self, model_id: str) -> bool:
        return model_id in self._responses

    def count_tokens(self, messages) -> int:
        return sum(len(m.content.split()) for m in messages)

    async def complete(self, req: CompletionRequest) -> CompletionResponse:
        text = self._responses.get(req.model, "mock response")
        return CompletionResponse(
            content=text, model=req.model,
            input_tokens=10, output_tokens=5,
            cost_usd=0.0, provider="mock",
        )

    async def stream(self, req):
        for word in self._responses.get(req.model, "mock").split():
            yield word + " "
